-- Data migration: HEAD catalog import for Glow Market (Task #233)
-- Applied directly to DB; this file serves as a reproducible record of the changes made.

-- Step 1: Ensure brand column exists (also in 0006_shop_product_brand.sql)
ALTER TABLE shop_products ADD COLUMN IF NOT EXISTS brand varchar(100);

-- Step 2: Ensure cat-clothing and cat-footwear categories exist
ON CONFLICT (id) DO NOTHING;

-- Step 3: Remove demo products (deactivate prod-wilson-pro due to FK constraint from shop_order_items)
DELETE FROM shop_products WHERE id IN ('prod-wilson-bag','prod-head-speed','prod-asics-gel','prod-nike-court','prod-luxilon-alu');
UPDATE shop_products SET is_active = false WHERE id = 'prod-wilson-pro';

-- Step 4: Set brand = 'HEAD' on all existing active products for default-academy
UPDATE shop_products SET brand = 'HEAD' WHERE academy_id = 'default-academy' AND is_active = true AND brand IS NULL;

-- Step 5: Import HEAD rackets (cat-rackets)

-- Step 5b: Import HEAD strings & grips (cat-strings)

-- Step 6: Set featured products (6 curated flagship items - one per major category)
UPDATE shop_products SET is_featured = false WHERE academy_id = 'default-academy';
UPDATE shop_products SET is_featured = true WHERE academy_id = 'default-academy' AND name = 'HEAD Speed MP Tennis Racquet';
UPDATE shop_products SET is_featured = true WHERE academy_id = 'default-academy' AND name = 'HEAD Hawk Touch Tennis String';
UPDATE shop_products SET is_featured = true WHERE academy_id = 'default-academy' AND name = 'HEAD Prime Tour Overgrip pack of 3 pcs';
UPDATE shop_products SET is_featured = true WHERE academy_id = 'default-academy' AND name LIKE '%Tour Backpack%Orange%';
UPDATE shop_products SET is_featured = true WHERE academy_id = 'default-academy' AND name = 'HEAD Sprint Pro 4.0 Men''s Tennis Shoes';
UPDATE shop_products SET is_featured = true WHERE academy_id = 'default-academy' AND name LIKE '%Club 25 Tech Polo%Men%'
  AND id = (SELECT id FROM shop_products WHERE academy_id = 'default-academy' AND name LIKE '%Club 25 Tech Polo%Men%' ORDER BY name LIMIT 1);

-- Step 7: Fix any image_url values that captured srcset content (cleanup to single 595x595 URL)
UPDATE shop_products 
SET image_url = REGEXP_REPLACE(image_url, '^.*?(https://www\.elpanonline\.com/wp-content/uploads/[^\s]+595x595\.[a-z]+).*$', '\1')
WHERE academy_id = 'default-academy' AND image_url LIKE '% %'
AND image_url ~ 'https://www\.elpanonline\.com/wp-content/uploads/[^\s]+595x595\.[a-z]+';

